(168, 2, 1166, 'خانم دکتر مژگان خادمی پور (داروخانه)', 'خانم دکتر مژگان خادمی پور', '', '09122757448', 'خیابان سردار جنگل خیابان مفتح داخل کوچه سینما طلوع داروخانه شبانه روزی خادمی پور', '', NULL, NULL, NULL, NULL, NULL, '', '', '', '', '', 'گیلان', 'فومن', '', '', '', '', NULL, 0, '', NULL, NULL),
(169, 2, 1167, 'خانم محمدی (همکار)', 'خانم محمدی', '', '09912763577', 'خیابان انقلاب بین خیابان شریعتی و بهار جنب بانک ملی ساختمان آریان ورودی غربی طبقه 5 واحد 1', '', NULL, NULL, NULL, NULL, NULL, '', '', '', '', '', 'تهران', 'تهران', '', '', '', '', NULL, 0, '', NULL, NULL),
(170, 2, 1168, 'آقای هادی کریمیان', 'آقای هادی کریمیان', '', '09171438613', 'بلوار امامت، امامت 10، پلاک 22 طبقه اول', '', NULL, NULL, NULL, NULL, NULL, '', '', '', '', '', 'کهگیلویه و بویراحمد', 'یاسوج', '', '', '', '', NULL, 0, '', NULL, NULL),
(171, 2, 1169, 'آقای احمدرضا جهانشاهی', 'آقای احمدرضا جهانشاهی', '', '09113733191', 'خیابان شهید مطهری نبش لاله ۱،دفتر خدمات پرستاری جهان مهرین\n', '', NULL, NULL, NULL, NULL, NULL, '', '', '', '', '', 'گلستان', 'بندرگز', '', '', '', '', NULL, 0, '', NULL, NULL),
