								10103510602								</p>\n							</td>\n							<td class=\"center\">\n								<p>\n									<b>شماره ثبت:\n									</b>\n																	</p>\n							</td>\n							<td class=\"center\">\n								<p>\n									<b>شماره اقتصادی:\n									</b>\n									10103510602								</p>\n							</td>\n							<td class=\"center\">\n								<p>\n									<b>تلفن / نمابر:</b>\n									۰۲۱۶۶۵۱۲۸۰۰								</p>\n							</td>\n						</tr>\n						<tr>\n							<td class=\"\" colspan=\"1\">\n								<p>\n									<b>کد پستی:</b>\n									1457655993								</p>\n							</td>\n							<td class=\"\" colspan=\"3\">\n								<p>\n									<b>آدرس:\n									</b>\n									استان تهران، شهر تهران، توحید، خیابان ستارخان، خیابان ستایش، پلاک 11، طبقه سوم								</p>\n							</td>\n						</tr>\n					</tbody>\n				</table>\n			</div>\n			<div style=\"width:100%;margin-top:5px;text-align:center;\">\n				<table style=\"width:100%;\">\n					<thead>\n						<tr class=\"stimol\" style=\"background-color:gray;\">\n							<th class=\"text-white\" style=\"width:80px\">ردیف</th>\n							<th class=\"text-white\">کالا/خدمات</th>\n							<th class=\"text-white\">شرح</th>\n							<th class=\"text-white\">تعداد / مقدار</th>\n							<th class=\"text-white\">مبلغ واحد</th>\n																					<th class=\"text-white\">مبلغ کل</th>\n						</tr>\n					</thead>\n					<tbody>\n																																																														<tr class=\"stimol\">\n									<td class=\"center item\">1</td>\n									<td class=\"center item\">\n										10767\n										-\n										دستکش لاتکس Gama سایز مدیوم</td>\n									<td class=\"center item\"></td>\n									<td class=\"center item\">\n										20\n										بسته\n									</td>\n									<td class=\"center item\">\n																																																																																																								3,470,000 ریال\n																			</td>\n																											<td class=\"center item\">69,400,000 ریال</td>\n								</tr>\n						