										-\n										چسب اتوکلاو</td>\n									<td class=\"center item\"></td>\n									<td class=\"center item\">\n										15\n										عدد\n									</td>\n									<td class=\"center item\">\n																																																																																																								452,000 ریال\n																			</td>\n																											<td class=\"center item\">6,780,000 ریال</td>\n								</tr>\n																																												<tr class=\"stimol\">\n									<td class=\"center item\">6</td>\n									<td class=\"center item\">\n										10764\n										-\n										کیسه اتوکلاو 60*40 (25 عددی)</td>\n									<td class=\"center item\"></td>\n									<td class=\"center item\">\n										2\n										بسته\n									</td>\n									<td class=\"center item\">\n																																																																																																								2,362,500 ریال\n																			</td>\n																											<td class=\"center item\">4,725,000 ریال</td>\n								</tr>\n																																												<tr class=\"stimol\">\n									<td class=\"center item\">7</td>\n									<td class=\"center item\">\n										10765\n										-\n										کیسه اتوکلاو 100*60 (12 عددی)</td>\n									<td class=\"center item\"></td>\n									<td class=\"center item\">\n										4\n										بسته\n									</td>\n									<td class=\"center item\">\n																																																																			3,125,000 ریال\n																			</td>\n																											<td class=\"center item\">12,500,000 ریال</td>\n								</tr>\n																															</tbody>\n				</table>\n			</div>\n			<div style=\"width:100%;margin-top:0px;text-align:center;\">\n				<table style=\"width:100%;\">\n					<tbody>\n						<tr class=\"stimol\">\n							<td class=\"item\" style=\"width:70%;padding:1%\">\n								<h4>\n									توضیحات:\n									\n									<br>\n																																					